  ('medical-tech-moex-02088', 'medical-tech', 'medical-tech-moex-114-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '在  小鼠T細胞依賴性的抗體產生中，下列有關細胞激素對於調控抗體類別轉換之組合，何者正確？', '["I FN-γ：抑制IgM、IgG1、IgE產生，促進IgG3及IgG2a產生", "I L-21：抑制IgG3、IgG1、IgA產生，促進IgM產生", "I L-4：抑制IgM、IgG3、IgG1、IgE產生", "T GF-β：抑制IgG3、IgG2b、IgA產生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "41bdf8dff33c", "answer_pdf_sha1": "864b0ac22417", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
