  ('medical-tech-moex-02092', 'medical-tech', 'medical-tech-moex-114-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '下  列有關體外淋巴球的增生試驗，何者錯誤？', '["使  用51Cr標定細胞", "使  用PHA刺激T細胞", "使  用ConA刺激T細胞", "一  般需要培養3～6天左右"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:07+00:00", "source_pdf_sha1": "41bdf8dff33c", "answer_pdf_sha1": "864b0ac22417", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
